import{c as l,Q as o,j as t,m as r}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"37. GitHub: Agent Rules Books","description":"","frontmatter":{"url":"https://github.com/ciembor/agent-rules-books","status":"SUCCESS","date_fetched":"2026-05-18T00:00:00.000Z","repository":"ciembor/agent-rules-books"},"headers":[],"relativePath":"research/ai-articles/37-github-ciembor-agent-rules-books.md","filePath":"research/ai-articles/37-github-ciembor-agent-rules-books.md","lastUpdated":1779894392000}'),e={name:"research/ai-articles/37-github-ciembor-agent-rules-books.md"};function a(n,i,s,g,u,h){return o(),t("div",null,[...i[0]||(i[0]=[r('<h1 id="_37-github-agent-rules-books" tabindex="-1">37. GitHub: Agent Rules Books <a class="header-anchor" href="#_37-github-agent-rules-books" aria-label="Permalink to &quot;37. GitHub: Agent Rules Books&quot;">​</a></h1><h2 id="核心摘要-繁體中文" tabindex="-1">核心摘要（繁體中文） <a class="header-anchor" href="#核心摘要-繁體中文" aria-label="Permalink to &quot;核心摘要（繁體中文）&quot;">​</a></h2><p>該儲存庫提供從經典軟體工程著作中提取的規則集合，專門設計用於 AI 編碼工具（Codex、Cursor、Claude Code）。提供三個版本（完整、精簡、迷你），並以驗證實驗證明規則有效性提升。</p><h3 id="涵蓋的-13-本軟體工程書籍" tabindex="-1">涵蓋的 13 本軟體工程書籍 <a class="header-anchor" href="#涵蓋的-13-本軟體工程書籍" aria-label="Permalink to &quot;涵蓋的 13 本軟體工程書籍&quot;">​</a></h3><ol><li><strong>A Philosophy of Software Design</strong>：深層模組、簡單介面和資訊隱藏</li><li><strong>Clean Architecture</strong>：穩定邊界和依賴規則</li><li><strong>Clean Code</strong>：可讀性、命名和小型函數</li><li><strong>Code Complete</strong>：構造實踐、防禦性編程和測試</li><li><strong>Designing Data-Intensive Applications</strong>：可靠性、可擴展性和一致性</li><li><strong>Domain-Driven Design</strong>：領域建模和無所不在的語言</li><li><strong>Domain-Driven Design Distilled</strong>：實用的 DDD 入門</li><li><strong>Implementing Domain-Driven Design</strong>：聚合體和領域事件</li><li><strong>Patterns of Enterprise Application Architecture</strong>：企業應用設計模式</li><li><strong>Refactoring</strong>：安全改進程式碼結構的方法</li><li><strong>Refactoring.Guru</strong>：實用的重構過程和代碼異味</li><li><strong>Release It!</strong>：生產環境的系統可靠性</li><li><strong>The Pragmatic Programmer</strong>：實用的軟體開發方法</li><li><strong>Working Effectively with Legacy Code</strong>：安全修改困難程式碼</li></ol><h3 id="規則版本選項" tabindex="-1">規則版本選項 <a class="header-anchor" href="#規則版本選項" aria-label="Permalink to &quot;規則版本選項&quot;">​</a></h3><p><strong>完整版（Full）</strong></p><ul><li>詳細的參考資料</li><li>包含完整解釋和背景</li><li>適合學習和深度理解</li></ul><p><strong>精簡版（Mini）</strong></p><ul><li>推薦用於大多數實踐應用</li><li>平衡詳細度和簡潔性</li><li>在驗證實驗中表現最佳</li></ul><p><strong>迷你版（Nano）</strong></p><ul><li>針對內容預算有限的情況</li><li>極簡規則集合</li><li>適合快速參考</li></ul><h3 id="規則涵蓋的關鍵主題" tabindex="-1">規則涵蓋的關鍵主題 <a class="header-anchor" href="#規則涵蓋的關鍵主題" aria-label="Permalink to &quot;規則涵蓋的關鍵主題&quot;">​</a></h3><p><strong>代碼品質</strong></p><ul><li>命名約定和慣例</li><li>函數設計和責任單一性</li><li>簡單性和複雜度管理</li></ul><p><strong>架構設計</strong></p><ul><li>邊界清晰性</li><li>依賴注入和反轉</li><li>關注點分離（Separation of Concerns）</li></ul><p><strong>領域建模</strong></p><ul><li>無所不在的語言（Ubiquitous Language）</li><li>有限上下文（Bounded Contexts）</li><li>聚合體（Aggregates）和領域事件</li></ul><p><strong>重構與改進</strong></p><ul><li>安全的重構技術</li><li>代碼異味識別</li><li>行為保護（Behavioral Preservation）</li></ul><p><strong>生產系統</strong></p><ul><li>可靠性原則</li><li>故障處理和恢復</li><li>可觀測性和監控</li><li>電路斷路器（Circuit Breakers）</li></ul><p><strong>遺留代碼</strong></p><ul><li>特徵測試（Characterization Tests）</li><li>接縫模型（Seam Model）</li><li>漸進式改進</li></ul><h3 id="驗證與效果評估" tabindex="-1">驗證與效果評估 <a class="header-anchor" href="#驗證與效果評估" aria-label="Permalink to &quot;驗證與效果評估&quot;">​</a></h3><p>儲存庫包含驗證實驗結果：</p><ul><li><strong>應用規則的版本</strong>：重構 A Philosophy of Software Design 時達到約 74/100 評分</li><li><strong>對照組（無規則）</strong>：僅得 46/100 評分</li><li><strong>改進幅度</strong>：約 61% 的質量提升</li></ul><p><strong>結論</strong>：使用具體規則列表比僅提及書籍名稱更有效。</p><h3 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h3><p>規則可用於多種場景：</p><ul><li>集成至 <code>AGENTS.md</code> 或 <code>.claude/</code> 配置</li><li>作為 Claude Code 的技能和提示</li><li>作為 Cursor 或 GitHub Copilot 的指導</li><li>專案級別的編碼標準</li></ul><hr><h2 id="關鍵數據-引用" tabindex="-1">關鍵數據/引用 <a class="header-anchor" href="#關鍵數據-引用" aria-label="Permalink to &quot;關鍵數據/引用&quot;">​</a></h2><h3 id="驗證實驗成果" tabindex="-1">驗證實驗成果 <a class="header-anchor" href="#驗證實驗成果" aria-label="Permalink to &quot;驗證實驗成果&quot;">​</a></h3><blockquote><p>應用具體規則列表的版本在重構任務中獲得約 74/100 的評分，而對照組僅得 46/100。</p></blockquote><p><strong>關鍵發現</strong>：</p><ul><li>規則版本 vs 對照：+61% 品質提升</li><li>Mini 版本與完整版性能相近</li><li>具體規則優於一般建議</li></ul><h3 id="核心原則" tabindex="-1">核心原則 <a class="header-anchor" href="#核心原則" aria-label="Permalink to &quot;核心原則&quot;">​</a></h3><p>儲存庫強調的統一主題：</p><ul><li><strong>簡單性優先</strong>：複雜系統難以維護和演進</li><li><strong>邊界清晰</strong>：明確的責任分離和依賴流向</li><li><strong>可測試性</strong>：代碼應設計成可測試的</li><li><strong>可觀測性</strong>：生產系統需要明確的可見性</li><li><strong>漸進改進</strong>：安全的重構而非大規模重寫</li></ul><h3 id="推薦應用流程" tabindex="-1">推薦應用流程 <a class="header-anchor" href="#推薦應用流程" aria-label="Permalink to &quot;推薦應用流程&quot;">​</a></h3><ol><li><strong>選擇合適版本</strong>：大多數情況選 Mini 版本</li><li><strong>集成至工作流程</strong>：納入代理提示或 <code>.claude/</code> 規則</li><li><strong>組織成類別</strong>：按書籍或主題分組</li><li><strong>定期審視</strong>：隨著專案演進更新和補充</li></ol><hr><h2 id="mit-授權" tabindex="-1">MIT 授權 <a class="header-anchor" href="#mit-授權" aria-label="Permalink to &quot;MIT 授權&quot;">​</a></h2><p>該儲存庫採用 MIT 授權，允許自由使用和修改。</p><hr><h2 id="重要說明" tabindex="-1">重要說明 <a class="header-anchor" href="#重要說明" aria-label="Permalink to &quot;重要說明&quot;">​</a></h2><p>這些規則是「受啟發於」而非官方再現；它們補充但不替代閱讀實際書籍。建議將規則作為快速參考，配合原著進行深度學習。</p>',49)])])}const p=l(e,[["render",a]]);export{d as __pageData,p as default};
